import { useState } from "react";
import "./sidebar.css";
import {
  LineStyle,
  Timeline,
  TrendingUp,
  PermIdentity,
  Storefront,
  AttachMoney,
  BarChart,
  MailOutline,
  DynamicFeed,
  ChatBubbleOutline,
  WorkOutline,
  Report
} from "@material-ui/icons";
import { Link } from "react-router-dom";

export default function Sidebar() {
  const [homeIsActive, setHomeIsActive] = useState(false);
  const [analyticsIsActive, setAnalyticsIsActive] = useState(false);
  const [salesIsActive, setSalesIsActive] = useState(false);
  const [usersIsActive, setUsersIsActive] = useState(false);
  const [productsIsActive, setProductsIsActive] = useState(false);
  const [transactionsIsActive, setTransactionsIsActive] = useState(false);
  const [reportsIsActive, setReportsIsActive] = useState(false);
  const [mailIsActive, setMailIsActive] = useState(false);
  const [feedbackIsActive, setFeedbackIsActive] = useState(false);
  const [messagesIsActive, setMessagesIsActive] = useState(false);
  const [manageIsActive, setManageIsActive] = useState(false);


  const handleClick = (name) => {
    switch(name) {
      case 'home':
        setHomeIsActive(true);
        setAnalyticsIsActive(false);
        setSalesIsActive(false);
        setUsersIsActive(false);
        setProductsIsActive(false);
        setTransactionsIsActive(false);
        setReportsIsActive(false);
        setMailIsActive(false);
        setFeedbackIsActive(false);
        setMessagesIsActive(false);
        setManageIsActive(false);
        break;
      case 'analytics':
        setHomeIsActive(false);
        setAnalyticsIsActive(true);
        setSalesIsActive(false);
        setUsersIsActive(false);
        setProductsIsActive(false);
        setTransactionsIsActive(false);
        setReportsIsActive(false);
        setMailIsActive(false);
        setFeedbackIsActive(false);
        setMessagesIsActive(false);
        setManageIsActive(false);
        break;
      case 'sales':
        setHomeIsActive(false);
        setAnalyticsIsActive(false);
        setSalesIsActive(true);
        setUsersIsActive(false);
        setProductsIsActive(false);
        setTransactionsIsActive(false);
        setReportsIsActive(false);
        setMailIsActive(false);
        setFeedbackIsActive(false);
        setMessagesIsActive(false);
        setManageIsActive(false);
        break;
      case 'users':
        setHomeIsActive(false);
        setAnalyticsIsActive(false);
        setSalesIsActive(false);
        setUsersIsActive(true);
        setProductsIsActive(false);
        setTransactionsIsActive(false);
        setReportsIsActive(false);
        setMailIsActive(false);
        setFeedbackIsActive(false);
        setMessagesIsActive(false);
        setManageIsActive(false);
        break;
      case 'products':
        setHomeIsActive(false);
        setAnalyticsIsActive(false);
        setSalesIsActive(false);
        setUsersIsActive(false);
        setProductsIsActive(true);
        setTransactionsIsActive(false);
        setReportsIsActive(false);
        setMailIsActive(false);
        setFeedbackIsActive(false);
        setMessagesIsActive(false);
        setManageIsActive(false);
        break;
      case 'transactions':
        setHomeIsActive(false);
        setAnalyticsIsActive(false);
        setSalesIsActive(false);
        setUsersIsActive(false);
        setProductsIsActive(false);
        setTransactionsIsActive(true);
        setReportsIsActive(false);
        setMailIsActive(false);
        setFeedbackIsActive(false);
        setMessagesIsActive(false);
        setManageIsActive(false);
        break;
      case 'reports':
        setHomeIsActive(false);
        setAnalyticsIsActive(false);
        setSalesIsActive(false);
        setUsersIsActive(false);
        setProductsIsActive(false);
        setTransactionsIsActive(false);
        setReportsIsActive(true);
        setMailIsActive(false);
        setFeedbackIsActive(false);
        setMessagesIsActive(false);
        setManageIsActive(false);
        break;
      case 'mail':
        setHomeIsActive(false);
        setAnalyticsIsActive(false);
        setSalesIsActive(false);
        setUsersIsActive(false);
        setProductsIsActive(false);
        setTransactionsIsActive(false);
        setReportsIsActive(false);
        setMailIsActive(true);
        setFeedbackIsActive(false);
        setMessagesIsActive(false);
        setManageIsActive(false);
        break;
      case 'feedback':
        setHomeIsActive(false);
        setAnalyticsIsActive(false);
        setSalesIsActive(false);
        setUsersIsActive(false);
        setProductsIsActive(false);
        setTransactionsIsActive(false);
        setReportsIsActive(false);
        setMailIsActive(false);
        setFeedbackIsActive(true);
        setMessagesIsActive(false);
        setManageIsActive(false);
        break;
      case 'messages':
        setHomeIsActive(false);
        setAnalyticsIsActive(false);
        setSalesIsActive(false);
        setUsersIsActive(false);
        setProductsIsActive(false);
        setTransactionsIsActive(false);
        setReportsIsActive(false);
        setMailIsActive(false);
        setFeedbackIsActive(false);
        setMessagesIsActive(true);
        setManageIsActive(false);
        break;
      case 'manage':
        setHomeIsActive(false);
        setAnalyticsIsActive(false);
        setSalesIsActive(false);
        setUsersIsActive(false);
        setProductsIsActive(false);
        setTransactionsIsActive(false);
        setReportsIsActive(false);
        setMailIsActive(false);
        setFeedbackIsActive(false);
        setMessagesIsActive(false);
        setManageIsActive(true);
        break;
      default:
        setHomeIsActive(true);
        setAnalyticsIsActive(false);
        setSalesIsActive(false);
        setUsersIsActive(false);
        setProductsIsActive(false);
        setTransactionsIsActive(false);
        setReportsIsActive(false);
        setMailIsActive(false);
        setFeedbackIsActive(false);
        setMessagesIsActive(false);
        setManageIsActive(false);
    }
  }
  return (
    <div className="sidebar">
      <div className="sidebarWrapper">
        <div className="sidebarMenu">
          <h3 className="sidebarTitle">Dashboard</h3>
          <ul className="sidebarList">
            <Link to="/" className="link">
              <li className={homeIsActive ? "sidebarListItem active" : "sidebarListItem"} onClick={() => handleClick('home')}>
                <LineStyle className="sidebarIcon" />
                Home
              </li>
            </Link>
            <li className={analyticsIsActive ? "sidebarListItem active" : "sidebarListItem"} onClick={() => handleClick('analytics')}>
              <Timeline className="sidebarIcon" />
              Analytics
            </li>
            <Link to="/sales" className="link">
              <li className={salesIsActive ? "sidebarListItem active" : "sidebarListItem"} onClick={() => handleClick('sales')}>
                <TrendingUp className="sidebarIcon" />
                Sales
              </li>
            </Link>
          </ul>
        </div>
        <div className="sidebarMenu">
          <h3 className="sidebarTitle">Quick Menu</h3>
          <ul className="sidebarList">
            <Link to="/users" className="link">
              <li className={usersIsActive ? "sidebarListItem active" : "sidebarListItem"} onClick={() => handleClick('users')}>
                <PermIdentity className="sidebarIcon" />
                Users
              </li>
            </Link>
            <Link to="/products" className="link">
              <li className={productsIsActive ? "sidebarListItem active" : "sidebarListItem"} onClick={() => handleClick('products')}>
                <Storefront className="sidebarIcon" />
                Products
              </li>
            </Link>
            <li className={transactionsIsActive ? "sidebarListItem active" : "sidebarListItem"} onClick={() => handleClick('transactions')}>
              <AttachMoney className="sidebarIcon" />
              Transactions
            </li>
            <li className={reportsIsActive ? "sidebarListItem active" : "sidebarListItem"} onClick={() => handleClick('reports')}>
              <BarChart className="sidebarIcon" />
              Reports
            </li>
          </ul>
        </div>
        <div className="sidebarMenu">
          <h3 className="sidebarTitle">Notifications</h3>
          <ul className="sidebarList">
            <li className={mailIsActive ? "sidebarListItem active" : "sidebarListItem"} onClick={() => handleClick('mail')}>
              <MailOutline className="sidebarIcon" />
              Mail
            </li>
            <li className={feedbackIsActive ? "sidebarListItem active" : "sidebarListItem"} onClick={() => handleClick('feedback')}>
              <DynamicFeed className="sidebarIcon" />
